/// Composes a base character with a combining character using the
/// precomputed NFC table.
pub fn compose_nfc(base: char, combining: char) -> Option<char> {
    let b = base as u32;
    let c = combining as u32;
    for &(tb, tc, tr) in COMPOSE {
        if tb == b && tc == c {
            return char::from_u32(tr);
        }
    }
    None
}
